css:
.parental-page {
    font-family: "Helvetica", Arial, sans-serif;
    font-size: 14px;
    color: #000;
    padding: 28px 36px 20px 36px;
    line-height: 1.7;
}

.top-right {
    text-align: right;
    font-weight: 700;
    font-size: 16px;
    margin-bottom: 18px;
}

.title-main {
    text-align: center;
    font-weight: 700;
    font-size: 18px;
    text-transform: uppercase;
    line-height: 1.4;
}

.title-sub {
    text-align: center;
    font-weight: 700;
    font-size: 18px;
    text-transform: uppercase;
    margin-bottom: 32px;
    line-height: 1.4;
}

.paragraph {
    text-align: justify;
    margin-bottom: 18px;
}

.intro-text {
    margin-bottom: 12px;
}

.inline-field {
    display: inline-block;
    border-bottom: 1px dotted #000;
    min-height: 16px;
    vertical-align: bottom;
    line-height: 1.2;
    padding: 0 4px 2px 4px;
}

.w-parent-name {
    min-width: 250px;
}

.w-student-name {
    min-width: 250px;
}

.w-programme {
    min-width: 180px;
}

.w-semester {
    min-width: 100px;
}

.w-year {
    min-width: 70px;
}

.w-student-no {
    min-width: 140px;
}

.undertaking-list {
    margin: 0 0 18px 18px;
    padding-left: 16px;
}

.undertaking-list li {
    margin-bottom: 10px;
    text-align: justify;
    padding-left: 6px;
}

.details-section {
    margin-top: 26px;
    width: 100%;
}

.left-block {
    width: 58%;
    float: left;
}

.right-block {
    width: 34%;
    float: right;
    text-align: center;
}

.stamp-note {
    padding-top: 10px;
    font-size: 14px;
}

.detail-line {
    margin-bottom: 8px;
    white-space: nowrap;
}

.dot-fill {
    display: inline-block;
    min-width: 180px;
    border-bottom: 1px dotted #000;
    padding: 0 4px 2px 4px;
    margin-left: 2px;
    vertical-align: bottom;
    white-space: normal;
}

.student-block {
    margin-top: 28px;
    width: 58%;
}

.committee-block {
    width: 34%;
    margin-left: auto;
    margin-top: 20px;
    text-align: left;
    line-height: 1.8;
}

.short-line {
    display: inline-block;
    min-width: 120px;
    border-bottom: 1px dotted #000;
    height: 14px;
    vertical-align: bottom;
}

.clearfix::after {
    content: "";
    display: block;
    clear: both;
}

@media print {
    .parental-page {
        padding: 20px 28px;
    }
}
